import React, { useState } from "react";

export default function DepositScreen({ onDeposit, goBack }) {
  const [amount, setAmount] = useState("");

  const handleDeposit = () => {
    if (!amount || isNaN(amount) || amount <= 0) return;
    onDeposit(parseFloat(amount));
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      {/* Header with back button */}
      <div className="flex items-center mb-6">
        <button
          onClick={goBack}
          className="text-teal-600 font-medium mr-4"
        >
          ← Back
        </button>
        <h1 className="text-2xl font-bold">Deposit Funds</h1>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 space-y-4">
        <p className="text-gray-500">Your current balance will be updated after deposit.</p>
        <input
          type="number"
          placeholder="Enter amount"
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-teal-500"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />
        <button
          onClick={handleDeposit}
          className="w-full py-3 bg-teal-600 text-white rounded-xl hover:bg-teal-700 transition-colors"
        >
          Deposit
        </button>
      </div>
    </div>
  );
}
